// Random Forest Prediction
float predict_rf(float features[N_FEATURES]) {
  float sum = 0.0f;
  
  // Sum predictions from all trees
  sum += tree_0(features);
  sum += tree_1(features);
  sum += tree_2(features);
  sum += tree_3(features);
  sum += tree_4(features);
  sum += tree_5(features);
  sum += tree_6(features);
  sum += tree_7(features);
  sum += tree_8(features);
  sum += tree_9(features);
  sum += tree_10(features);
  sum += tree_11(features);
  sum += tree_12(features);
  sum += tree_13(features);
  sum += tree_14(features);
  sum += tree_15(features);
  sum += tree_16(features);
  sum += tree_17(features);
  sum += tree_18(features);
  sum += tree_19(features);
  sum += tree_20(features);
  sum += tree_21(features);
  sum += tree_22(features);
  sum += tree_23(features);
  sum += tree_24(features);
  sum += tree_25(features);
  sum += tree_26(features);
  sum += tree_27(features);
  sum += tree_28(features);
  sum += tree_29(features);
  sum += tree_30(features);
  sum += tree_31(features);
  sum += tree_32(features);
  sum += tree_33(features);
  sum += tree_34(features);
  sum += tree_35(features);
  sum += tree_36(features);
  sum += tree_37(features);
  sum += tree_38(features);
  sum += tree_39(features);
  sum += tree_40(features);
  sum += tree_41(features);
  sum += tree_42(features);
  sum += tree_43(features);
  sum += tree_44(features);
  sum += tree_45(features);
  sum += tree_46(features);
  sum += tree_47(features);
  sum += tree_48(features);
  sum += tree_49(features);
  
  // Average predictions
  float prediction = sum / 50.0f;
  
  // Clip to valid range [0, 100]
  if (prediction < 0.0f) prediction = 0.0f;
  if (prediction > 100.0f) prediction = 100.0f;
  
  return prediction;
}

// Helper: Calculate time features from hour
void calculate_time_features(int hour, float* sin_hour, float* cos_hour, int* time_period) {
  // Cyclic encoding for hour
  *sin_hour = sin(2.0f * PI * hour / 24.0f);
  *cos_hour = cos(2.0f * PI * hour / 24.0f);
  
  // Time period encoding
  if (hour < 6) {
    *time_period = 0;  // Early Morning
  } else if (hour < 12) {
    *time_period = 1;  // Morning
  } else if (hour < 17) {
    *time_period = 2;  // Afternoon
  } else if (hour < 21) {
    *time_period = 3;  // Evening
  } else {
    *time_period = 4;  // Night
  }
}

// High-level prediction function
int predict_led_brightness(float ambient_light, int motion_detected, int hour, int day_of_week) {
  float features[N_FEATURES];
  float sin_hour, cos_hour;
  int time_period;
  
  // Calculate time features
  calculate_time_features(hour, &sin_hour, &cos_hour, &time_period);
  
  // Prepare feature array
  features[FEAT_AMBIENT_LIGHT] = ambient_light;
  features[FEAT_MOTION_DETECTED] = (float)motion_detected;
  features[FEAT_SIN_HOUR] = sin_hour;
  features[FEAT_COS_HOUR] = cos_hour;
  features[FEAT_TIME_PERIOD] = (float)time_period;
  features[FEAT_DAY_OF_WEEK] = (float)day_of_week;
  
  // Get prediction
  float prediction = predict_rf(features);
  
  // Return as integer percentage
  return (int)round(prediction);
}

// Get current day of week (0=Sunday in RTC, convert to 0=Monday)
int get_day_of_week_from_rtc(int rtc_day_of_week) {
  // RTC: 0=Sunday, 1=Monday, ..., 6=Saturday
  // Model: 0=Monday, 1=Tuesday, ..., 6=Sunday
  if (rtc_day_of_week == 0) return 6;  // Sunday
  return rtc_day_of_week - 1;
}

